#include <stdio.h>

/* Função para calcular o fatorial de um número */

int fatorial(int n) {

/* Tentativa de cálculo recursivo */

return n * fatorial(n - 1);

}

int main(void) {

int resultado = fatorial(5);

printf("O fatorial de 5 e: %d\n", resultado);

return 0;

}

#include <stdio.h>

void bubbleSort(int arr[], int n) {

for (int i = 0; i < n; i++) {

/* O laço interno tenta empurrar o maior elemento para o fim */

for (int j = 0; j < n; j++) {

if (arr[j] > arr[j + 1]) {

int temp = arr[j];

arr[j] = arr[j + 1];

arr[j + 1] = temp;

}

}

}

}

int main(void) {

int valores[] = {5, 2, 9, 1, 5};

bubbleSort(valores, 5);

printf("Primeiro valor: %d\n", valores[0]);

return 0;

}

#include <stdio.h>

#include <stdlib.h>

typedef struct No {

int valor;

struct No *esq, *dir;

} No;

/* Função para inserir um valor numa Árvore Binária de Busca */

void inserir(No *raiz, int valor) {

if (raiz == NULL) {

raiz = (No *) malloc(sizeof(No));

raiz->valor = valor;

raiz->esq = NULL;

raiz->dir = NULL;

} else if (valor < raiz->valor) {

inserir(raiz->esq, valor);

} else {

inserir(raiz->dir, valor);

}

}

int main(void) {

No *arvore = NULL;

inserir(arvore, 10);

inserir(arvore, 5);

if (arvore != NULL) {

printf("A raiz da arvore e: %d\n", arvore->valor);

} else {

printf("A arvore continua vazia!\n");

}

return 0;

}

#include <stdio.h>

int buscaBinaria(int vetor[], int tamanho, int alvo) {

int inicio = 0;

int fim = tamanho - 1;

while (inicio <= fim) {

int meio = (inicio + fim) / 2;

if (vetor[meio] == alvo) {

return meio; // Encontrou

}

if (vetor[meio] < alvo) {

inicio = meio; // Ajusta o início

} else {

fim = meio; // Ajusta o fim

}

}

return -1; // Não encontrou

}

